// src/pages/instructor/InstructorProfile.jsx
import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import { instructorAPI } from '../../api/client';
import './instructor.css';

// ── Модалка редактирования авто ───────────────────────────────────────────────
function CarModal({ profile, onClose, onSaved }) {
  const [form, setForm] = useState({
    car_brand:    profile?.car_brand    || '',
    car_color:    profile?.car_color    || '',
    car_plate:    profile?.car_plate    || '',
    car_type_kpp: profile?.car_type_kpp || 'МКПП',
  });
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState('');

  const save = async () => {
    setLoading(true); setErr('');
    try {
      await instructorAPI.updateCar(form);
      onSaved();
    } catch (e) {
      setErr(e.response?.data?.detail || JSON.stringify(e.response?.data) || 'Ошибка');
    } finally { setLoading(false); }
  };

  return (
    <div className="inst-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="inst-modal inst-modal-middle">
        <div className="inst-modal-header">
          <div className="inst-modal-title">Марка автомобиля</div>
          <button className="inst-modal-close" onClick={onClose}>✕</button>
        </div>

        <div className="inst-modal-field">
          <label className="inst-form-label">Марка автомобиля</label>
          <input className="inst-form-input" placeholder="Lada Granta"
            value={form.car_brand} onChange={e => setForm(p => ({ ...p, car_brand: e.target.value }))} />
        </div>
        <div className="inst-modal-field">
          <label className="inst-form-label">Цвет</label>
          <input className="inst-form-input" placeholder="Белый"
            value={form.car_color} onChange={e => setForm(p => ({ ...p, car_color: e.target.value }))} />
        </div>
        <div className="inst-modal-field">
          <label className="inst-form-label">Регистрационный номер</label>
          <input className="inst-form-input" placeholder="X000XX774"
            value={form.car_plate} onChange={e => setForm(p => ({ ...p, car_plate: e.target.value }))} />
        </div>
        <div className="inst-modal-field">
          <label className="inst-form-label">Тип КПП</label>
          <select className="inst-form-input" value={form.car_type_kpp}
            onChange={e => setForm(p => ({ ...p, car_type_kpp: e.target.value }))}>
            <option value="МКПП">МКПП (механика)</option>
            <option value="АКПП">АКПП (автомат)</option>
          </select>
        </div>

        {err && <p style={{ color: 'var(--red)', fontSize: 13, margin: '4px 0' }}>{err}</p>}

        <button className="inst-btn inst-btn-primary" style={{ width: '100%', marginTop: 8 }}
          onClick={save} disabled={loading}>
          {loading ? <span className="spinner" /> : 'Сохранить'}
        </button>
      </div>
    </div>
  );
}

// ── Модалка лимита ────────────────────────────────────────────────────────────
function LimitModal({ profile, onClose, onSaved }) {
  const [limit, setLimit] = useState(profile?.weekly_limit ?? 3);
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState('');

  const save = async () => {
    setLoading(true); setErr('');
    try {
      await instructorAPI.updateLimit({ weekly_limit: limit });
      onSaved();
    } catch (e) {
      setErr(e.response?.data?.detail || JSON.stringify(e.response?.data) || 'Ошибка');
    } finally { setLoading(false); }
  };

  return (
    <div className="inst-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="inst-modal inst-modal-middle">
        <div className="inst-modal-header">
          <div className="inst-modal-title">Лимит занятий</div>
          <button className="inst-modal-close" onClick={onClose}>✕</button>
        </div>

        <p style={{ fontSize: 14, color: 'var(--text-muted)', marginBottom: 16, lineHeight: 1.5 }}>
          Максимальное количество занятий в неделю, на которое может записаться студент.
        </p>

        <div className="inst-limit-row">
          <button className="inst-limit-btn" onClick={() => setLimit(p => Math.max(1, p - 1))}>−</button>
          <span className="inst-limit-val">{limit}</span>
          <button className="inst-limit-btn" onClick={() => setLimit(p => Math.min(10, p + 1))}>+</button>
        </div>

        {err && <p style={{ color: 'var(--red)', fontSize: 13, margin: '4px 0' }}>{err}</p>}

        <button className="inst-btn inst-btn-primary" style={{ width: '100%', marginTop: 16 }}
          onClick={save} disabled={loading}>
          {loading ? <span className="spinner" /> : 'Сохранить'}
        </button>
      </div>
    </div>
  );
}

// ── Основная страница профиля ─────────────────────────────────────────────────
export default function InstructorProfile() {
  const { logout } = useAuth();
  const navigate   = useNavigate();

  const [profile, setProfile]   = useState(null);
  const [loading, setLoading]   = useState(true);
  const [modal, setModal]       = useState(null); // null | 'car' | 'limit'

  const load = () => {
    instructorAPI.getProfile()
      .then(r => setProfile(r.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, []);

  const fullName = profile
    ? [profile.last_name, profile.first_name, profile.patronymic].filter(Boolean).join(' ')
    : '—';

  const carLabel = profile?.car_brand
    ? `${profile.car_color ? profile.car_color + ' ' : ''}${profile.car_brand} ${profile.car_plate || ''}`.trim()
    : 'Не указан';

  return (
    <div className="inst-page">
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
        <h1 className="inst-title" style={{ margin: 0 }}>Профиль</h1>
        <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
          <button className="inst-icon-btn">📋</button>
          <button className="inst-icon-btn">🔔</button>
        </div>
      </div>

      {loading ? (
        <div className="inst-loading"><span className="spinner" style={{ borderTopColor: 'var(--blue)' }} /></div>
      ) : (
        <>
          {/* Avatar + name */}
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', marginBottom: 28 }}>
            <div className="inst-profile-avatar-lg">
              <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
                <circle cx="24" cy="18" r="10" fill="#b0b8c9" />
                <ellipse cx="24" cy="42" rx="18" ry="10" fill="#b0b8c9" />
              </svg>
            </div>
            <div style={{ fontSize: 16, fontWeight: 700, marginTop: 12, textAlign: 'center' }}>
              {fullName}
            </div>
          </div>

          {/* Car card */}
          <div className="inst-info-card" onClick={() => setModal('car')}>
            <div className="inst-info-card-header">
              <span className="inst-info-card-title">Автомобиль</span>
              <span className="inst-info-card-edit">✎</span>
            </div>
            <div className="inst-info-card-value">{carLabel}</div>
          </div>

          {/* Limit card */}
          <div className="inst-info-card" onClick={() => setModal('limit')}>
            <div className="inst-info-card-header">
              <span className="inst-info-card-title">Лимит</span>
              <span className="inst-info-card-edit">✎</span>
            </div>
            <div className="inst-info-card-value" style={{ fontSize: 14, color: 'var(--text-muted)', lineHeight: 1.5 }}>
              Максимальное количество занятий в неделю, на которое может записаться студент&nbsp;—&nbsp;
              <strong style={{ color: 'var(--text)' }}>{profile?.weekly_limit ?? 3}</strong>.
            </div>
          </div>

          {/* Logout */}
          <button
            className="inst-btn inst-btn-blue"
            style={{ width: '100%', marginTop: 24 }}
            onClick={() => { logout(); navigate('/login'); }}
          >
            Выйти
          </button>
        </>
      )}

      {/* Modals */}
      {modal === 'car'   && <CarModal   profile={profile} onClose={() => setModal(null)} onSaved={() => { setModal(null); load(); }} />}
      {modal === 'limit' && <LimitModal profile={profile} onClose={() => setModal(null)} onSaved={() => { setModal(null); load(); }} />}
    </div>
  );
}
